11	type ProtocolMode string
12	type OperationMode string
13	
14	type Config struct {
15		raw syncer.Config
16	}
17	
18	const ProtocolAuto ProtocolMode = validation.ProtocolAuto
19	const ProtocolV1 ProtocolMode = validation.ProtocolV1
20	const ProtocolV2 ProtocolMode = validation.ProtocolV2
21	
22	const ModeSync OperationMode = "sync"
23	const ModeReplicate OperationMode = "replicate"
24	
25	type RefMapping struct {
26		Source string
27		Target string
28	}
29	
30	type Endpoint struct {
31		URL                    string
32		FollowInfoRefsRedirect bool
33	}
34	
35	type EndpointAuth struct {
36		Username      string
37		Token         string
38		BearerToken   string
39		SkipTLSVerify bool
40	}
41	
42	type RefScope struct {
43		Branches           []string
44		Mappings           []RefMapping
45		AllRefs            bool
46		ExcludeRefPrefixes []string
47	}
48	
49	type SyncPolicy struct {
50		Mode           OperationMode
51		IncludeTags    bool
52		ForceWithLease bool
53		ForceBlind     bool
54		Prune          bool
55		BestEffort     bool
56		Protocol       ProtocolMode
57	}
58	
59	func ProbeConfig(source Endpoint, sourceAuth EndpointAuth, target *Endpoint, targetAuth EndpointAuth, protocol ProtocolMode, includeTags, allRefs, collectStats bool, excludeRefPrefixes []string, httpClient *http.Client) Config {
60		cfg := syncer.Config{
61			Source:             ToSyncerEndpoint(source, sourceAuth),
62			HTTPClient:         httpClient,
63			IncludeTags:        includeTags,
64			AllRefs:            allRefs,
65			ExcludeRefPrefixes: append([]string(nil), excludeRefPrefixes...),
66			ShowStats:          collectStats,
67			ProtocolMode:       protocolString(protocol),
68		}
69		if target != nil {
70			cfg.Target = ToSyncerEndpoint(*target, targetAuth)
71		}
72		return Config{raw: cfg}
73	}
74	
75	func SyncConfig(source Endpoint, sourceAuth EndpointAuth, target Endpoint, targetAuth EndpointAuth, scope RefScope, policy SyncPolicy, collectStats, dryRun bool, httpClient *http.Client) Config {
76		return Config{raw: syncer.Config{
77			Source:                 ToSyncerEndpoint(source, sourceAuth),
78			Target:                 ToSyncerEndpoint(target, targetAuth),
79			HTTPClient:             httpClient,
80			Branches:               append([]string(nil), scope.Branches...),
81			Mappings:               ToValidationMappings(scope.Mappings),
82			AllRefs:                scope.AllRefs,
83			ExcludeRefPrefixes:     append([]string(nil), scope.ExcludeRefPrefixes...),
84			IncludeTags:            policy.IncludeTags,
85			DryRun:                 dryRun,
86			ShowStats:              collectStats,
87			Mode:                   operationModeString(policy.Mode),
88			ForceWithLease:         policy.ForceWithLease,
89			ForceBlind:             policy.ForceBlind,
90			Prune:                  policy.Prune,
91			BestEffort:             policy.BestEffort,
92			ProtocolMode:           protocolString(policy.Protocol),
93			MaterializedMaxObjects: syncer.DefaultMaterializedMaxObjects,
94		}}
95	}
96	
97	func Probe(ctx context.Context, cfg Config) (syncer.ProbeResult, error) {
98		result, err := syncer.Probe(ctx, cfg.raw)
99		if err != nil {
100			return syncer.ProbeResult{}, err //nolint:wrapcheck // pass-through layer, caller wraps with context
101		}
102		return result, nil
103	}
104	
105	func Run(ctx context.Context, cfg Config) (syncer.Result, error) {
106		result, err := syncer.Run(ctx, cfg.raw)
107		if err != nil {
108			return syncer.Result{}, err //nolint:wrapcheck // pass-through layer, caller wraps with context
109		}
110		return result, nil
111	}
112	
113	func ToSyncerEndpoint(endpoint Endpoint, auth EndpointAuth) syncer.Endpoint {
114		return syncer.Endpoint{
115			URL:                    endpoint.URL,
116			Username:               auth.Username,
117			Token:                  auth.Token,
118			BearerToken:            auth.BearerToken,
119			SkipTLSVerify:          auth.SkipTLSVerify,
120			FollowInfoRefsRedirect: endpoint.FollowInfoRefsRedirect,
121		}
122	}
123	
124	func protocolString(mode ProtocolMode) string {
125		if mode == "" {
126			return string(ProtocolAuto)
127		}
128		return string(mode)
129	}
130	
131	func operationModeString(mode OperationMode) string {
132		if mode == "" {
133			return string(ModeSync)
134		}
135		return string(mode)
136	}
137	
138	func ToValidationMappings(mappings []RefMapping) []validation.RefMapping {
139		out := make([]validation.RefMapping, 0, len(mappings))
140		for _, mapping := range mappings {
141			out = append(out, validation.RefMapping{
142				Source: mapping.Source,
143				Target: mapping.Target,
144			})
145		}
146		return out
147	}
