223	func (c *Client) buildProbeConfig(ctx context.Context, req ProbeRequest) (syncer.Config, error) {
224		source, err := c.resolveEndpoint(ctx, req.Source, gitsync.SourceRole)
225		if err != nil {
226			return syncer.Config{}, err
227		}
228		cfg := syncer.Config{
229			Source:             source,
230			HTTPClient:         c.httpClient,
231			IncludeTags:        req.IncludeTags,
232			AllRefs:            req.AllRefs,
233			ExcludeRefPrefixes: append([]string(nil), req.ExcludeRefPrefixes...),
234			ShowStats:          req.Options.CollectStats,
235			MeasureMemory:      req.Options.MeasureMemory,
236			Progress:           req.Options.Progress,
237			ProtocolMode:       protocolString(req.Protocol),
238			Verbose:            req.Options.Verbose,
239		}
240		if req.Target != nil {
241			target, err := c.resolveEndpoint(ctx, *req.Target, gitsync.TargetRole)
242			if err != nil {
243				return syncer.Config{}, err
244			}
245			cfg.Target = target
246		}
247		return cfg, nil
248	}
249	
250	func (c *Client) buildSyncConfig(ctx context.Context, req SyncRequest) (syncer.Config, error) {
251		source, err := c.resolveEndpoint(ctx, req.Source, gitsync.SourceRole)
252		if err != nil {
253			return syncer.Config{}, err
254		}
255		target, err := c.resolveEndpoint(ctx, req.Target, gitsync.TargetRole)
256		if err != nil {
257			return syncer.Config{}, err
258		}
259		maxObjects := req.Options.MaterializedMaxObjects
260		if maxObjects == 0 {
261			maxObjects = DefaultMaterializedMaxObjects
262		}
263		return syncer.Config{
264			Source:                 source,
265			Target:                 target,
266			HTTPClient:             c.httpClient,
